class Solution {
public:
    bool canVisitAllRooms(vector<vector<int>>& rooms) {
        int size = rooms.size();
        set<int> mp;
        stack<int> stack;
        stack.push(0);

        while (!stack.empty()) {
        mp.insert(stack.top());
        assign(rooms[stack.top()], stack, mp);
    }
        if(size == mp.size())
        return true;
        return false;



    }
private:
    void assign(vector<int> room, stack<int>& stack, set<int>& mp){
        stack.pop();
        vector<int>::iterator ptr;
        for (ptr = room.begin(); ptr < room.end(); ptr++) {
        if(mp.contains(*ptr)){
            continue;
        } else{
            stack.push(*ptr);
        }
        }


    }
};
